import React, { useState } from 'react';
import BarcodeScanner from './components/BarcodeScanner';
import Cart from './components/Cart';
import Checkout from './components/Checkout';
import BillSuccess from './components/BillSuccess';
import Toast from './components/Toast';
import { productService, billService } from './services/api';
import config from './config';
import './App.css';

function App() {
  const [cartItems, setCartItems] = useState([]);
  const [showCheckout, setShowCheckout] = useState(false);
  const [generatedBill, setGeneratedBill] = useState(null);
  const [loading, setLoading] = useState(false);
  const [toast, setToast] = useState(null);

  const showToast = (message, type = 'info') => {
    setToast({ message, type });
  };

  const closeToast = () => setToast(null);

  /**
   * ✅ SAFE BARCODE HANDLER
   */
  const handleBarcodeScan = async (rawSku) => {
    try {
      setLoading(true);

      const response = await productService.getProductBySKU(rawSku);

      if (!response.success) {
        showToast(response.message || 'Product not found', 'error');
        return;
      }

      const product = response.data;
      const sku = product.sku; // 🔥 SINGLE SOURCE OF TRUTH

      setCartItems(prevItems => {
        const existing = prevItems.find(item => item.sku === sku);

        if (existing) {
          return prevItems.map(item =>
            item.sku === sku
              ? { ...item, quantity: item.quantity + 1 }
              : item
          );
        }

        return [
          ...prevItems,
          {
            sku,
            name: product.name,
            price: product.price,
            quantity: 1
          }
        ];
      });

      showToast(`${product.name} added to cart`, 'success');

    } catch (error) {
      console.error('Scan error:', error);
      showToast(error.message || 'Failed to fetch product', 'error');
    } finally {
      setLoading(false);
    }
  };

  /**
   * ✅ QUANTITY UPDATE BY SKU
   */
  const handleUpdateQuantity = (sku, newQty) => {
    if (newQty < 1) return;

    setCartItems(prev =>
      prev.map(item =>
        item.sku === sku
          ? { ...item, quantity: newQty }
          : item
      )
    );
  };

  /**
   * ✅ REMOVE BY SKU
   */
  const handleRemoveItem = (sku) => {
    setCartItems(prev => prev.filter(item => item.sku !== sku));
    showToast('Item removed from cart', 'info');
  };

  const handleCheckout = () => {
    if (cartItems.length === 0) {
      showToast('Cart is empty', 'warning');
      return;
    }
    setShowCheckout(true);
  };

  const handleCheckoutCancel = () => setShowCheckout(false);

  /**
   * ✅ BACKEND-ONLY BILL CALCULATION
   */
  const handleCheckoutConfirm = async ({ discountPercent }) => {
    try {
      setLoading(true);

      const response = await billService.createBill({
        items: cartItems,
        discountPercent
      });

      if (!response.success) {
        throw new Error(response.message || 'Bill creation failed');
      }

      setGeneratedBill(response.data);
      setCartItems([]);
      setShowCheckout(false);
      showToast('Bill generated successfully!', 'success');

    } catch (error) {
      showToast(error.message || 'Failed to generate bill', 'error');
    } finally {
      setLoading(false);
    }
  };

  const handleNewBill = () => {
    setGeneratedBill(null);
    setCartItems([]);
  };

  if (generatedBill) {
    return (
      <div className="app">
        <BillSuccess bill={generatedBill} onNewBill={handleNewBill} />
        {toast && <Toast {...toast} onClose={closeToast} />}
      </div>
    );
  }

  return (
    <div className="app">
      <header className="app-header">
        <h1>{config.STORE_NAME}</h1>
        <p>Smart Billing System</p>
      </header>

      <main className="app-main">
        <BarcodeScanner onScan={handleBarcodeScan} />
        <Cart
          items={cartItems}
          onUpdateQuantity={handleUpdateQuantity}
          onRemoveItem={handleRemoveItem}
          onCheckout={handleCheckout}
        />
      </main>

      {showCheckout && (
        <Checkout
          items={cartItems}
          onConfirm={handleCheckoutConfirm}
          onCancel={handleCheckoutCancel}
        />
      )}

      {loading && <div className="loading-overlay">Processing...</div>}
      {toast && <Toast {...toast} onClose={closeToast} />}
    </div>
  );
}

export default App;
